// Immutable Builder -- each setter returns a new Builder
class MealBuilder {
    final String bun; final int patties;
    MealBuilder(String bun, int patties) { this.bun = bun; this.patties = patties; }
    MealBuilder withBun(String b) { return new MealBuilder(b, this.patties); }
    MealBuilder withPatties(int p) { return new MealBuilder(this.bun, p); }
}

// Share a base, derive safely
