MealBuilder large = base.withPatties(3);  // base unchanged!

// Step Builder: compiler enforces order
interface BunStep     { PattyStep setBun(String bun); }
interface PattyStep   { SauceStep setPatties(int n); }
interface SauceStep   { BuildStep setSauce(String s); }
interface BuildStep   { Meal build(); }

// Usage: MUST follow order
Meal m = MealBuilder.start()
    .setBun("Sesame")     // returns PattyStep
    .setPatties(2)        // returns SauceStep
    .setSauce("BBQ")      // returns BuildStep
    .build();

