// Solution: Recursive generics (self-type idiom)
abstract class MealBuilder<T extends MealBuilder<T>> {
    protected abstract T self();
    T setBun(String bun) { this.bun = bun; return self(); }
}

class GourmetMealBuilder extends MealBuilder<GourmetMealBuilder> {
    protected GourmetMealBuilder self() { return this; }
    GourmetMealBuilder setTruffle(boolean t) { this.truffle = t; return self(); }
}

// Now chaining works:
new GourmetMealBuilder().setBun("Brioche").setTruffle(true).build();

