class NotificationBuilderFactory {
    static Notification.Builder create(String channel) {
        return switch (channel) {
            case "email" -> new Notification.Builder()
                .setChannel("EMAIL")
                .setPriority("MEDIUM");   // email defaults
            case "sms" -> new Notification.Builder()
                .setChannel("SMS")
                .setPriority("HIGH");     // sms defaults
            default -> throw new IllegalArgumentException("Unknown: " + channel);
        };
    }
}

