class Response<T> {
    private final int status;
    private final T data;
    private final String message;

    static <T> Builder<T> builder() { return new Builder<>(); }

    static class Builder<T> {
        private int status;
        private T data;
        private String message;

        Builder<T> setStatus(int s) { this.status = s; return this; }
        Builder<T> setData(T d) { this.data = d; return this; }
        Builder<T> setMessage(String m) { this.message = m; return this; }
        Response<T> build() { return new Response<>(status, data, message); }
    }
}

